use core::fmt::Write;
extern crate alloc;
use alloc::vec::Vec;

struct FileHandle {
    size_remaining: usize,
    buffer: Vec<u8>,
}

impl FileHandle {
    fn new(initial_capacity: usize) -> Self {
        FileHandle {
            size_remaining: 0,
            buffer: Vec::with_capacity(initial_capacity),
        }
    }

    fn process_chunk(&mut self, chunk: &[u8]) -> bool {
        if chunk.is_empty() { return false; }
        self.size_remaining += chunk.len();
        self.buffer.extend_from_slice(chunk);
        true
    }

    fn is_complete(&self) -> bool {
        !self.buffer.is_empty()
    }

    fn get_data(&self) -> &[u8] {
        &self.buffer
    }
}

struct VirusScanner {
    signature_db: &'static str,
}

impl VirusScanner {
    fn new(db: &'static str) -> Self {
        VirusScanner { signature_db: db }
    }

    fn scan(&self, data: &[u8]) -> Result<(), String> {
        if data.len() < 10 {
            return Ok(());
        }
        let potential_match = &data[..10];
        if core::str::from_utf8(potential_match).unwrap().contains("bad") {
            Err(format!("Virus detected based on signature: {}", self.signature_db))
        } else {
            Ok(()) 
        }
    }
}

fn handle_upload(mut file_data: Vec<u8>) -> Result<(), String> {
    let mut handle = FileHandle::new(1024 * 5);
    handle.buffer = file_data;

    let scanner = VirusScanner::new("KnownMalwarev3");

    if let Err(e) = scanner.scan(handle.get_data()) {
        return Err(format!("Scan failed: {}", e));
    }

    println!("Successfully processed and scanned {} bytes.", handle.get_data().len());
    Ok(())
}

fn main() {
    let raw_upload_stream: Vec<u8> = b"somefileheaderbadcontentpayload".to_vec();
