use core::panic;
struct SensorState {
    is_initialized: bool,
    last_reading: i32,
    door_open_count: u8,
}
impl Default for SensorState {
    fn default() -> Self {
        SensorState {
            is_initialized: false,
            last_reading: 0,
            door_open_count: 0,
        }
    }
}
struct SensorNode {
    state: SensorState,
}
impl SensorNode {
    fn new() -> Self {
        SensorNode {
            state: SensorState::default(),
        }
    }

    fn initialize(&mut self) {
        if !self.state.is_initialized {
            println!("System booting up and calibrating sensors...");
            self.state.last_reading = 42;
            self.state.is_initialized = true;
        }
    }

    fn check_door_status(&mut self) -> bool {
        if !self.state.is_initialized {
            return false;
        }
        let is_open = self.state.door_open_count > 0;
        if is_open {
            println!("Door detected as OPEN.");
            self.state.door_open_count = self.state.door_open_count.saturating_sub(1);
        } else {
            println!("Door status check: CLOSED.");
        }
        is_open
    }

    fn read_sensor(&mut self, ambient_value: i32) {
        if !self.state.is_initialized {
            return;
        }
        println!("Reading sensor data: {}", ambient_value);
        self.state.last_reading = ambient_value;
    }

    fn run_cycle(&mut self, ambient_value: i32) -> bool {
        self.read_sensor(ambient_value);
        let door_open = self.check_door_status();
        if door_open && self.state.last_reading > 50 {
            println!("ALERT: Door open while reading high sensor value!");
        }
        true
    }
}

fn main() -> ! {
