    }
}

use std::io::{self, Write};

struct SequenceParser {
    buffer: Vec<u8>,
}

impl SequenceParser {
    fn new() -> Self {
        SequenceParser { buffer: Vec::new() }
    }

    fn parse_and_print(&mut self, input_data: &[u8]) -> Result<(), io::Error> {
        self.buffer.clear();
        for &byte in input_data.iter() {
            if byte == b',' {
                if !self.buffer.is_empty() {
                    let s = String::from_utf8_lossy(&self.buffer);
                    write!(io::stdout(), "{}", s).unwrap();
                    writeln!(io::stdout()).unwrap();
                }
                self.buffer.clear();
            } else if byte != b'n' && byte != b'r' {
                self.buffer.push(byte);
            }
        }

        if !self.buffer.is_empty() {
            let s = String::from_utf8_lossy(&self.buffer);
            write!(io::stdout(), "{}", s).unwrap();
            writeln!(io::stdout()).unwrap();
        }

        Ok(()) 
    }
}

fn main() {
    let raw_input = b"ATGC,TATAnGCAT,AATTG";
    let mut parser = SequenceParser::new();
    if let Err(_) = parser.parse_and_print(raw_input) {
        eprintln!("Error processing input.");
    }
}
